273:         ConnectorStateInfo stateInfo = requestHandler.completeOrForwardRequest(cb, forwardingPath, "POST", headers, queryParameters, null, new TypeReference<>() {
274:         }, new IdentityTranslator<>(), forward);
275:         return Response.accepted().entity(stateInfo).build();
